memberdef.initializer:
do {                                                       \
  uint32_t val;                                            \
  do {                                                     \
    val = __LDREXW((__IO uint32_t *)&(REG)) | (BIT);       \
  } while ((__STREXW(val,(__IO uint32_t *)&(REG))) != 0U); \
} while(0)

do {                                                       \
  uint32_t val;                                            \
  do {                                                     \
    val = __LDREXW((__IO uint32_t *)&(REG)) & ~(BIT);      \
  } while ((__STREXW(val,(__IO uint32_t *)&(REG))) != 0U); \
} while(0)

do {                                                                     \
  uint32_t val;                                                          \
  do {                                                                   \
    val = (__LDREXW((__IO uint32_t *)&(REG)) & ~(CLEARMSK)) | (SETMASK); \
  } while ((__STREXW(val,(__IO uint32_t *)&(REG))) != 0U);               \
} while(0)

